def solution(old_schema, new_schema):
    breaking = []
    non_breaking = []
    old_keys = set(old_schema)
    new_keys = set(new_schema)

    for f in sorted(old_keys - new_keys):
        breaking.append(f'field_removed:{f}')
    for f in sorted(new_keys - old_keys):
        non_breaking.append(f'field_added:{f}')
