def solution(incidents, overlap_minutes):
    out = []
    n = len(incidents)
    for i in range(n):
        for j in range(i + 1, n):
            a = incidents[i]
            b = incidents[j]
            if a.get('region') != b.get('region'):
                continue
            if a.get('provider') == b.get('provider'):
                continue
            start = max(a.get('start', 0), b.get('start', 0))
            end = min(a.get('end', 0), b.get('end', 0))
            overlap = end - start
            if overlap >= overlap_minutes:
                out.append({
                    'providers': sorted([a.get('provider'), b.get('provider')]),
                    'region': a.get('region'),
                    'overlap': overlap
                })
    out.sort(key=lambda x: (x['region'], x['providers'][0], x['providers'][1]))
    return out

