from collections import defaultdict, deque

def solution(logs, limit, window_seconds):
    per_user = defaultdict(list)
    for row in logs:
        if ',' not in row:
            continue
        t_raw, user = row.split(',', 1)
        user = user.strip()
        try:
            t = int(t_raw.strip())
        except ValueError:
            continue
        if user:
            per_user[user].append(t)

    bad = []
    for user, arr in per_user.items():
        arr.sort()
        q = deque()
        for t in arr:
            q.append(t)
            while q and t - q[0] >= window_seconds:
                q.popleft()
            if len(q) > limit:
                bad.append(user)
                break

    return ','.join(sorted(bad))

