from collections import defaultdict, deque

def solution(records, max_count, window_seconds):
    by_account = defaultdict(list)
    for row in records:
        parts = row.split(',')
        if len(parts) != 3:
            continue
        t_raw, account, _ = parts
        try:
            t = int(t_raw.strip())
        except ValueError:
            continue
        account = account.strip()
        if account:
            by_account[account].append(t)

    flagged = []
    for account, arr in by_account.items():
        arr.sort()
        q = deque()
        for t in arr:
            q.append(t)
            while q and t - q[0] >= window_seconds:
                q.popleft()
            if len(q) > max_count:
                flagged.append(account)
                break

    return ','.join(sorted(flagged))

def solution(latencies_ms, threshold, window_size):
    n = len(latencies_ms)
    if window_size <= 0 or window_size > n:
        return 0

    s = sum(latencies_ms[:window_size])
    breaches = 1 if (s / window_size) > threshold else 0

    for i in range(window_size, n):
        s += latencies_ms[i] - latencies_ms[i - window_size]
        if (s / window_size) > threshold:
            breaches += 1

    return breaches

