from collections import Counter

def solution(rows, strategies):
    def missing(v):
        return v is None or v == ''

    fillers = {}
    for col, st in strategies.items():
        kind = st.get('type')
        values = [r.get(col) for r in rows if not missing(r.get(col))]
        if kind == 'constant':
            fillers[col] = st.get('value')
        elif kind == 'mean':
            nums = [float(v) for v in values]
            fillers[col] = sum(nums) / len(nums) if nums else 0.0
        elif kind == 'mode':
            if values:
                counts = Counter(values)
                fillers[col] = sorted(counts.items(), key=lambda x: (-x[1], str(x[0])))[0][0]
            else:
                fillers[col] = None
        else:
            fillers[col] = None

    out = []
    for row in rows:
        nr = dict(row)
        for col in strategies:
            if missing(nr.get(col)):
                nr[col] = fillers[col]
        out.append(nr)
    return out

