import math

def solution(series, baseline_window, sigma):
    if baseline_window <= 0:
        return []
    spikes = []
    for i in range(baseline_window, len(series)):
        base = series[i - baseline_window:i]
        mean = sum(base) / baseline_window
        var = sum((x - mean) ** 2 for x in base) / baseline_window
        std = math.sqrt(var)
        if series[i] > mean + sigma * std:
            spikes.append(i)
    return spikes

