                 ((p.charAt(j - 2) == '.' || p.charAt(j - 2) == s.charAt(i - 1))
                  && dp[i - 1][j]);
    } else if (p.charAt(j - 1) == '.' || p.charAt(j - 1) == s.charAt(i - 1)) {
      dp[i][j] = dp[i - 1][j - 1];
    }
