// Approach: Parent map + ancestor set
// Time: O(n)  Space: O(n)
if (tree.length == 0 || tree[0] == -1) return -1;
Map<Integer, Integer> parent = new HashMap<>();
parent.put(tree[0], -1);
Queue<Integer> queue = new LinkedList<>();
queue.add(0);
int i = 1;
while (!queue.isEmpty() && i < tree.length) {
  int nodeIndex = queue.poll();
  if (i < tree.length && tree[i] != -1) {
    parent.put(tree[i], tree[nodeIndex]);
    queue.add(i);
  }
  i++;
  if (i < tree.length && tree[i] != -1) {
    parent.put(tree[i], tree[nodeIndex]);
    queue.add(i);
  }
  i++;
}
Set<Integer> ancestors = new HashSet<>();
while (p != -1 && parent.containsKey(p)) {
  ancestors.add(p);
  p = parent.get(p);
}
if (p != -1) ancestors.add(p);
while (q != -1 && !ancestors.contains(q)) {
  q = parent.get(q);
}
return q;

