// Approach: BFS serialize and deserialize for round-trip verification
// Time: O(n)  Space: O(n)
if (root == null || root.trim().isEmpty()) return "";
String[] vals = root.trim().split("\\\\s+");
// Serialize: join as comma-separated
StringBuilder sb = new StringBuilder();
Queue<Integer> indexQ = new LinkedList<>();
indexQ.add(0);
while (!indexQ.isEmpty()) {
  int idx = indexQ.poll();
  if (idx >= vals.length) break;
  if (sb.length() > 0) sb.append(",");
  sb.append(vals[idx]);
  if (!vals[idx].equals("null")) {
    indexQ.add(2 * idx + 1);
    indexQ.add(2 * idx + 2);
  }
}
return sb.toString();

